 1	import React, { useState } from 'react';
 2	import { useNavigate } from 'react-router-dom-v5-compat';
 3	
 4	import ExternalLink from '@kubevirt-utils/components/ExternalLink/ExternalLink';
 5	import { documentationURL } from '@kubevirt-utils/constants/documentation';
 6	import { ALL_NAMESPACES_SESSION_KEY } from '@kubevirt-utils/hooks/constants';
 7	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 8	import { useActiveNamespace } from '@openshift-console/dynamic-plugin-sdk';
 9	import {
10	  Button,
11	  ButtonVariant,
12	  EmptyState,
13	  EmptyStateActions,
14	  EmptyStateBody,
15	  EmptyStateFooter,
16	  EmptyStateHeader,
17	  EmptyStateIcon,
18	  EmptyStateVariant,
19	} from '@patternfly/react-core';
20	import { NetworkIcon } from '@patternfly/react-icons';
21	import { createURL } from '@virtualmachines/details/tabs/overview/utils/utils';
22	
23	import { installOrRemoveCheckupsNetworkPermissions } from '../utils/utils';
24	
25	import './checkups-network-list-empty-state.scss';
26	
27	const CheckupsNetworkListEmptyState = ({ isPermitted, nadsInNamespace }) => {
28	  const { t } = useKubevirtTranslation();
29	  const navigate = useNavigate();
30	  const [namespace] = useActiveNamespace();
31	  const [isLoading, setIsLoading] = useState<boolean>(false);
32	
33	  return (
34	    <EmptyState variant={EmptyStateVariant.lg}>
35	      <EmptyStateHeader
36	        headingLevel="h4"
37	        icon={<EmptyStateIcon icon={NetworkIcon} />}
38	        titleText={<>{t('No network latency checkups found')}</>}
39	      />
40	
41	      <EmptyStateBody>
42	        {t('To get started, install permissions and then run a checkup')}
43	      </EmptyStateBody>
44	
45	      <EmptyStateFooter>
46	        <EmptyStateActions>
47	          <Button
48	            isDisabled={
49	              !isPermitted ||
50	              !nadsInNamespace ||
51	              isLoading ||
52	              namespace === ALL_NAMESPACES_SESSION_KEY
53	            }
54	            onClick={() => navigate(createURL('form', location.pathname))}
55	          >
56	            {t('Run checkup')}
57	          </Button>
58	        </EmptyStateActions>
59	        <EmptyStateActions>
60	          <Button
61	            onClick={async () => {
62	              setIsLoading(true);
63	              await installOrRemoveCheckupsNetworkPermissions(namespace, isPermitted);
64	              setIsLoading(false);
65	            }}
66	            isDisabled={!nadsInNamespace || isLoading}
67	            isLoading={isLoading}
68	            variant={isLoading ? ButtonVariant.plain : ButtonVariant.secondary}
69	          >
70	            {!isLoading && isPermitted ? t('Remove permissions') : t('Install permissions')}
71	          </Button>
72	        </EmptyStateActions>
73	        {!nadsInNamespace && (
74	          <p className="CheckupsNetworkListEmptyState--title__namespace text-muted">
75	            {t('Add a NetworkAttachmentDefinition to this namespace in order to use checkups')}
76	          </p>
77	        )}
78	        <EmptyStateActions>
79	          <ExternalLink
80	            href={documentationURL.CHECKUPS_LATENCY}
81	            text={t('Learn more about network latency checkups')}
82	          />
83	        </EmptyStateActions>
84	      </EmptyStateFooter>
85	    </EmptyState>
86	  );
87	};
88	
89	export default CheckupsNetworkListEmptyState;

